"""
Parabolic Exhaustion Test Fixtures
===================================

Synthetic bar DataFrames for testing the ParabolicExhaustion detector.
Each fixture tests one specific aspect of the pattern.

Stock universe: sub-$20 small caps, 25%+ extension required.
All fixtures have 15+ bars (min_bars_required=15).
"""

import pandas as pd
from datetime import datetime, timedelta


def _make_bars(data: list) -> pd.DataFrame:
    """Create DataFrame from OHLCV tuples."""
    base_time = datetime(2026, 1, 15, 9, 30)
    rows = []
    for i, (o, h, l, c, v) in enumerate(data):
        rows.append({
            "timestamp": base_time + timedelta(minutes=i),
            "open": o,
            "high": h,
            "low": l,
            "close": c,
            "volume": v,
        })
    return pd.DataFrame(rows)


